	channels := 1
	bytesPerFrame := 960
	samplesPerFrame := 480
	if stereo {
		channels = 2
		bytesPerFrame = 1920
		samplesPerFrame = 960 // interleaved L/R
	}

	silence := make([]int16, samplesPerFrame)

	// Build the sink chain: jitter buffer → volume control → original sink
	var finalSink Sink
	if jitterBuf {
		// Create jitter buffer with configurable delay
		jitter := NewJitterBuffer(sink, jitterDelayMs, samplesPerFrame)
		finalSink = NewJitterSink(jitter, sink)
		log.Printf("Engine: using jitter buffer with %dms delay", jitterDelayMs)
	} else {
		finalSink = sink
		log.Printf("Engine: jitter buffer disabled")
	}

	// Wrap with volume controller
	volumeCtrl := NewVolumeController(DefaultVolume)
	volSink := &volumeSink{inner: finalSink, ctrl: volumeCtrl}

	return &Engine{
		sink:            volSink,
		jitter:          nil, // only set if jitter buffer is used
		ytDlpPath:       ytDlpPath,
		stopCh:          make(chan struct{}),
		doneCh:          make(chan struct{}),
		channels:        channels,
		bytesPerFrame:   bytesPerFrame,
		samplesPerFrame: samplesPerFrame,
